const horizonResponse = $input.item.json;
const statusCode = horizonResponse.statusCode;

if (statusCode !== 200) {
  return [{
    json: {
      valid: false,
      error: `Horizon returned ${statusCode} — transaction not found or not yet indexed.`
    }
  }];
}

const body = horizonResponse.body;
const operations = body?._embedded?.records || [];

// Pull expected values from the original webhook input
const expectedDestination = $('Webhook: Receive Task').item.json.body.agentPublicKey;
const expectedAmount = parseFloat($('Webhook: Receive Task').item.json.body.price || '1');

const match = operations.find(op =>
  op.type === 'payment' &&
  op.to === expectedDestination &&
  parseFloat(op.amount) >= expectedAmount
);

if (!match) {
  return [{
    json: {
      valid: false,
      error: `No valid payment found. Expected ${expectedAmount} XLM to ${expectedDestination}.`
    }
  }];
}

return [{
  json: {
    valid: true,
    txHash: $('Webhook: Receive Task').item.json.headers['x-payment-hash'],
    paidAmount: match.amount,
    destination: match.to,
    from: match.from,
    task: $('Webhook: Receive Task').item.json.body.task
  }
}];

const serpData = $input.item.json;
const task = $('Is Payment Confirmed?').item.json.task;

// Extract the most useful parts of the SERP response
const organicResults = (serpData.organic_results || []).slice(0, 6).map(r => ({
  title: r.title,
  snippet: r.snippet,
  link: r.link
}));

const answerBox = serpData.answer_box
  ? `DIRECT ANSWER: ${serpData.answer_box.answer || serpData.answer_box.snippet || ''}`
  : '';

const knowledgeGraph = serpData.knowledge_graph
  ? `KNOWLEDGE GRAPH: ${serpData.knowledge_graph.description || ''}`
  : '';

const relatedQuestions = (serpData.related_questions || []).slice(0, 3).map(q =>
  `Q: ${q.question} → ${q.snippet}`
).join('\n');

const searchContext = [
  answerBox,
  knowledgeGraph,
  'TOP SEARCH RESULTS:',
  ...organicResults.map((r, i) => `[${i+1}] ${r.title}\n    ${r.snippet}\n    Source: ${r.link}`),
  relatedQuestions ? `RELATED QUESTIONS:\n${relatedQuestions}` : ''
].filter(Boolean).join('\n\n');

return [{
  json: {
    task,
    searchContext,
    sourceCount: organicResults.length,
    txHash: $('Is Payment Confirmed?').item.json.txHash,
    paidAmount: $('Is Payment Confirmed?').item.json.paidAmount
  }
}];

