const groqResponse = $input.item.json;
const researchResult = groqResponse.choices?.[0]?.message?.content || 'Research complete.';
const usage = groqResponse.usage || {};

const meta = $('Extract & Format Search Results').item.json;

return [{
  json: {
    result: researchResult,
    meta: {
      agentId: 'research',
      agentName: 'Research Agent (n8n)',
      txHash: meta.txHash,
      paidAmount: `${meta.paidAmount} XLM`,
      network: 'Stellar Testnet',
      explorerUrl: `https://stellar.expert/explorer/testnet/tx/${meta.txHash}`,
      sourcesSearched: meta.sourceCount,
      tokensUsed: usage.total_tokens || 0,
      model: 'llama-3.3-70b-versatile',
      pipeline: 'n8n workflow · SerpAPI → Groq'
    }
  }
}];
